import { createFileRoute } from '@tanstack/react-router';
import React, { Suspense } from 'react';
import { PageTabs } from '@/components/PageTabs';
import { AttendeeTabs } from '@/constants/Routes';
import { PageLoader } from '@/components/ui/PageLoader';

const AttendeeSearch = React.lazy(() => import('@/pages/attendee/AttendeeSearch').then(m => ({ default: m.AttendeeSearch })));

function Page() {
  return (
    <PageTabs tabs={AttendeeTabs}>
      <Suspense fallback={<PageLoader />}>
        <AttendeeSearch initialMode="checkin" />
      </Suspense>
    </PageTabs>
  );
}

export const Route = createFileRoute('/_auth/attendee/checkin')({
  component: Page,
});

